SELECT ?item ?itemLabel ?parent ?parentLabel WHERE {
  ?item wdt:P279* wd:Q845945 .
  ?item wdt:P279 ?parent .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en,ja". }
}
LIMIT 80

SELECT ?prefecture ?prefectureLabel ?capital ?capitalLabel WHERE {
  ?prefecture wdt:P31 wd:Q50337 .
  OPTIONAL { ?prefecture wdt:P36 ?capital . }
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en,ja". }
}
LIMIT 60

SELECT ?item ?itemLabel ?parent ?parentLabel WHERE {
  ?item wdt:P279* wd:Q1088552 .
  ?item wdt:P279 ?parent .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
LIMIT 100

SELECT ?person ?personLabel ?field ?fieldLabel WHERE {
  ?person wdt:P166 ?award .
  ?award wdt:P31/wdt:P279* wd:Q7191 .
  ?person wdt:P101 ?field .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
LIMIT 80

SELECT ?lang ?langLabel ?paradigm ?paradigmLabel WHERE {
  ?lang wdt:P31 wd:Q9143 .
  ?lang wdt:P3966 ?paradigm .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
LIMIT 80
